import { readFileSync } from "node:fs";
import { join } from "node:path";
import { computeReachableSteps, renderMarkdown, TARGETS, } from "bitfab-flow";
import { describe, expect, it } from "vitest";
import { assistantFlow } from "./assistant.js";
const REPO_ROOT = join(__dirname, "..", "..", "..");
const ASSISTANT_PATHS = {
    claude: "bitfab-claude-plugin/commands/assistant.md",
    cursor: "bitfab-cursor-plugin/skills/bitfab-assistant/SKILL.md",
    codex: "bitfab-codex-plugin/skills/assistant/SKILL.md",
};
describe("renderMarkdown(assistantFlow)", () => {
    for (const targetName of Object.keys(ASSISTANT_PATHS)) {
        it(`matches the committed ${targetName} assistant skill byte-for-byte`, () => {
            const target = TARGETS[targetName];
            const generated = renderMarkdown(assistantFlow, target);
            const committedPath = join(REPO_ROOT, ASSISTANT_PATHS[targetName]);
            const committed = readFileSync(committedPath, "utf-8");
            expect(generated).toBe(committed);
        });
    }
});
describe("assistantFlow: target-gated Phase 0", () => {
    it("Phase 0 is unreachable for claude (codex enters there but claude doesn't)", () => {
        const reachable = computeReachableSteps(assistantFlow, "claude");
        expect(reachable.has("phase-0/resolve-plugin-dir")).toBe(false);
        expect(reachable.has("phase-0/run-status")).toBe(false);
    });
    it("Phase 0 is unreachable for cursor", () => {
        const reachable = computeReachableSteps(assistantFlow, "cursor");
        expect(reachable.has("phase-0/resolve-plugin-dir")).toBe(false);
        expect(reachable.has("phase-0/run-status")).toBe(false);
    });
    it("Phase 0 is reachable for codex (the only path codex enters through)", () => {
        const reachable = computeReachableSteps(assistantFlow, "codex");
        expect(reachable.has("phase-0/resolve-plugin-dir")).toBe(true);
        expect(reachable.has("phase-0/run-status")).toBe(true);
    });
    it("Phase 0 content does not appear in claude / cursor rendered output", () => {
        const claudeOutput = renderMarkdown(assistantFlow, TARGETS.claude);
        const cursorOutput = renderMarkdown(assistantFlow, TARGETS.cursor);
        expect(claudeOutput).not.toContain("Phase 0");
        expect(claudeOutput).not.toContain("BITFAB_PLUGIN_DIR");
        expect(cursorOutput).not.toContain("Phase 0");
        expect(cursorOutput).not.toContain("BITFAB_PLUGIN_DIR");
    });
    it("Phase 0 appears in codex rendered output", () => {
        const codexOutput = renderMarkdown(assistantFlow, TARGETS.codex);
        expect(codexOutput).toContain("## Phase 0: Status + Update Check");
        expect(codexOutput).toContain("BITFAB_PLUGIN_DIR");
    });
});
describe("assistantFlow: claude allowed-tools", () => {
    it("auto-derives Skill and Agent into the claude allowed-tools frontmatter", () => {
        const claudeOutput = renderMarkdown(assistantFlow, TARGETS.claude);
        const frontmatter = claudeOutput.split("---\n")[1] ?? "";
        expect(frontmatter).toContain('"Skill"');
        expect(frontmatter).toContain('"Agent"');
        expect(frontmatter).toContain('"AskUserQuestion"');
    });
    it("includes all four MCP tools (with the local plugin prefix) in claude allowed-tools", () => {
        const claudeOutput = renderMarkdown(assistantFlow, TARGETS.claude);
        const frontmatter = claudeOutput.split("---\n")[1] ?? "";
        expect(frontmatter).toContain("mcp__plugin_bitfab_Bitfab__list_trace_functions");
        expect(frontmatter).toContain("mcp__plugin_bitfab_Bitfab__search_traces");
        expect(frontmatter).toContain("mcp__plugin_bitfab_Bitfab__read_traces");
        expect(frontmatter).toContain("mcp__plugin_bitfab_Bitfab__update_agent_labels");
    });
});
describe("assistantFlow: dataset-gate loop", () => {
    it("confirm-dataset failure branch loops back to find-unlabeled", () => {
        const phase3 = assistantFlow.phases.find((p) => p.id === "phase-3");
        expect(phase3).toBeDefined();
        const confirm = phase3?.steps.find((s) => s.id === "confirm-dataset");
        expect(confirm?.kind).toBe("branch");
        if (confirm?.kind !== "branch") {
            throw new Error("expected branch step");
        }
        const failBranch = confirm.branches.find((b) => (b.when ?? "").includes("no validated failing"));
        expect(failBranch?.next).toBe("phase-3/find-unlabeled");
        const passBranch = confirm.branches.find((b) => (b.when ?? "").includes("at least one"));
        expect(passBranch?.next).toBe("phase-3/hold-in-context");
    });
});
describe("assistantFlow: edit-template-loop", () => {
    it("edit-template-loop is reachable from await-event for all targets", () => {
        for (const targetName of ["claude", "cursor", "codex"]) {
            const reachable = computeReachableSteps(assistantFlow, targetName);
            expect(reachable.has("phase-3/edit-template-loop")).toBe(true);
        }
    });
    it("edit-template-loop returns to await-event", () => {
        const phase3 = assistantFlow.phases.find((p) => p.id === "phase-3");
        expect(phase3).toBeDefined();
        const step = phase3?.steps.find((s) => s.id === "edit-template-loop");
        expect(step?.kind).toBe("action");
        if (step?.kind !== "action") {
            throw new Error("expected action step");
        }
        expect(step.next).toBe("phase-3/await-event");
    });
    it("await-event has a branch for template editing", () => {
        const phase3 = assistantFlow.phases.find((p) => p.id === "phase-3");
        const awaitEvent = phase3?.steps.find((s) => s.id === "await-event");
        expect(awaitEvent?.kind).toBe("branch");
        if (awaitEvent?.kind !== "branch") {
            throw new Error("expected branch step");
        }
        const templateBranch = awaitEvent.branches.find((b) => b.next === "phase-3/edit-template-loop");
        expect(templateBranch).toBeDefined();
        expect(templateBranch?.when).toContain("template");
    });
    it("includes template MCP tools in claude allowed-tools", () => {
        const claudeOutput = renderMarkdown(assistantFlow, TARGETS.claude);
        const frontmatter = claudeOutput.split("---\n")[1] ?? "";
        expect(frontmatter).toContain("mcp__plugin_bitfab_Bitfab__get_template_reference");
        expect(frontmatter).toContain("mcp__plugin_bitfab_Bitfab__get_template");
        expect(frontmatter).toContain("mcp__plugin_bitfab_Bitfab__update_template");
    });
});
describe("assistantFlow: detect-replay-capabilities", () => {
    it("detect-replay-capabilities exists in both phase-2 and phase-5", () => {
        const phase2 = assistantFlow.phases.find((p) => p.id === "phase-2");
        const phase5 = assistantFlow.phases.find((p) => p.id === "phase-5");
        expect(phase2?.steps.find((s) => s.id === "detect-replay-capabilities")).toBeDefined();
        expect(phase5?.steps.find((s) => s.id === "detect-replay-capabilities")).toBeDefined();
    });
    it("upgrade-replay-script exists in both phase-2 and phase-5", () => {
        const phase2 = assistantFlow.phases.find((p) => p.id === "phase-2");
        const phase5 = assistantFlow.phases.find((p) => p.id === "phase-5");
        expect(phase2?.steps.find((s) => s.id === "upgrade-replay-script")).toBeDefined();
        expect(phase5?.steps.find((s) => s.id === "upgrade-replay-script")).toBeDefined();
    });
    it("both detect steps are reachable for all targets", () => {
        for (const targetName of ["claude", "cursor", "codex"]) {
            const reachable = computeReachableSteps(assistantFlow, targetName);
            expect(reachable.has("phase-2/detect-replay-capabilities")).toBe(true);
            expect(reachable.has("phase-5/detect-replay-capabilities")).toBe(true);
        }
    });
    it("categorize-fixes routes to phase-5 detect-replay-capabilities", () => {
        const phase4 = assistantFlow.phases.find((p) => p.id === "phase-4");
        expect(phase4).toBeDefined();
        const categorize = phase4?.steps.find((s) => s.id === "categorize-fixes");
        expect(categorize?.kind).toBe("action");
        if (categorize?.kind !== "action") {
            throw new Error("expected action step");
        }
        const nextVal = categorize.next;
        expect(nextVal).not.toBeNull();
        if (typeof nextVal === "string") {
            expect(nextVal).toContain("detect-replay-capabilities");
        }
        else if (nextVal !== null) {
            for (const v of Object.values(nextVal.byMode)) {
                if (v !== null) {
                    expect(v).toContain("detect-replay-capabilities");
                }
            }
        }
    });
    it("phase-5 detect-replay-capabilities auto-skips when all flags present", () => {
        const phase5 = assistantFlow.phases.find((p) => p.id === "phase-5");
        expect(phase5).toBeDefined();
        const detect = phase5?.steps.find((s) => s.id === "detect-replay-capabilities");
        expect(detect?.kind).toBe("branch");
        if (detect?.kind !== "branch") {
            throw new Error("expected branch step");
        }
        const autoSkip = detect.branches.find((b) => b.when?.includes("all three flags"));
        expect(autoSkip?.next).toBe("phase-5/make-change");
    });
    it("phase-5 upgrade-replay-script continues to make-change", () => {
        const phase5 = assistantFlow.phases.find((p) => p.id === "phase-5");
        expect(phase5).toBeDefined();
        const upgrade = phase5?.steps.find((s) => s.id === "upgrade-replay-script");
        expect(upgrade?.kind).toBe("action");
        if (upgrade?.kind !== "action") {
            throw new Error("expected action step");
        }
        expect(upgrade.next).toBe("phase-5/make-change");
    });
    it("share-results loops back to make-change (skipping detect on subsequent iterations)", () => {
        const phase5 = assistantFlow.phases.find((p) => p.id === "phase-5");
        expect(phase5).toBeDefined();
        const share = phase5?.steps.find((s) => s.id === "share-results");
        expect(share?.kind).toBe("branch");
        if (share?.kind !== "branch") {
            throw new Error("expected branch step");
        }
        const continueBranch = share.branches.find((b) => b.next === "phase-5/make-change");
        expect(continueBranch).toBeDefined();
    });
});
describe("assistantFlow: per-target MCP prefix in intro", () => {
    it("claude intro mentions the long mcp__plugin_bitfab_Bitfab__* prefix", () => {
        const out = renderMarkdown(assistantFlow, TARGETS.claude);
        expect(out).toContain("mcp__plugin_bitfab_Bitfab__*");
    });
    it("cursor intro mentions the short mcp__Bitfab__* prefix (not the claude one)", () => {
        const out = renderMarkdown(assistantFlow, TARGETS.cursor);
        expect(out).toContain("mcp__Bitfab__*");
        expect(out).not.toContain("mcp__plugin_bitfab_Bitfab__*");
    });
    it("codex intro mentions the short mcp__Bitfab__* prefix and the blocking-process rule", () => {
        const out = renderMarkdown(assistantFlow, TARGETS.codex);
        expect(out).toContain("mcp__Bitfab__*");
        expect(out).toContain("Blocking-process rule");
    });
});
